// 簡單密碼雜湊（不用後端也能比對）
async function hashPassword(password) {
  const msgBuffer = new TextEncoder().encode(password + "mudao_salt_2024");
  const hashBuffer = await crypto.subtle.digest("SHA-256", msgBuffer);
  const hashArray = Array.from(new Uint8Array(hashBuffer));
  return hashArray.map(b => b.toString(16).padStart(2, "0")).join("");
}

// ── 雲端案件操作 ──
async function cloudSaveProject(project, ownerEmail) {
  try {
    const existing = await sbFetch(`projects?owner_email=eq.${encodeURIComponent(ownerEmail)}&id=eq.${project.id}&select=id`);
    const payload = { owner_email: ownerEmail, project_id: project.id, data: JSON.stringify(project), updated_at: new Date().toISOString() };
    if (Array.isArray(existing) && existing.length > 0) {
      await sbFetch(`projects?owner_email=eq.${encodeURIComponent(ownerEmail)}&project_id=eq.${project.id}`, { method: "PATCH", body: JSON.stringify({ data: JSON.stringify(project), updated_at: new Date().toISOString() }) });
    } else {
      await sbFetch("projects", { method: "POST", body: JSON.stringify(payload) });
    }
    return true;
  } catch (e) { console.error("雲端儲存失敗:", e); return false; }
}

async function cloudDeleteProject(projectId, ownerEmail) {
  try {
    await sbFetch(`projects?owner_email=eq.${encodeURIComponent(ownerEmail)}&project_id=eq.${projectId}`, { method: "DELETE" });
    return true;
  } catch (e) { console.error("雲端刪除失敗:", e); return false; }
}

async function cloudLoadProjects(currentUser, allUsers) {
  try {
    let data = [];
    if (currentUser.role === "manager" || currentUser.role === "director") {
      // 主管/總監看全部
      data = await sbFetch("projects?select=*&order=updated_at.desc");
    } else {
      // 其他人只看自己的 + 被加入的
      data = await sbFetch(`projects?select=*&order=updated_at.desc`);
    }
    if (!Array.isArray(data)) return [];
    const projects = data.map(row => {
      try { return JSON.parse(row.data); } catch { return null; }
    }).filter(Boolean);

    // 根據權限過濾
    if (currentUser.role === "manager") return projects;
    if (currentUser.role === "director") return projects;

    return projects.filter(p => {
      const userName = currentUser.name;
      if (p.ownerEmail === currentUser.email) return true;
      if (p.designer === userName) return true;
      if (p.assistant === userName) return true;
      if (p.siteManager === userName) return true;
      return false;
    });
  } catch (e) { console.error("雲端載入失敗:", e); return []; }
}

async function sbFetch(path, options = {}) {
  try {
    const res = await fetch(`${SUPABASE_URL}/rest/v1/${path}`, {
      headers: {
        "apikey": SUPABASE_KEY,
        "Authorization": `Bearer ${SUPABASE_KEY}`,
        "Content-Type": "application/json",
        "Prefer": options.method === "POST" ? "return=representation" : "return=representation",
        ...options.headers,
      },
      ...options,
    });
    if (res.status === 204) return [];
    const text = await res.text();
    if (!text) return [];
    try { return JSON.parse(text); } catch { return []; }
  } catch (e) {
    console.error("Supabase 連線失敗:", e);
    return [];
  }
}

