function calcWorkDays(startStr, endStr) {
  if (!startStr || !endStr) return null;
  const start = new Date(startStr);
  const end = new Date(endStr);
  if (end < start) return null;
  let days = 0;
  const cur = new Date(start);
  while (cur <= end) {
    const dow = cur.getDay();
    const ds = cur.toISOString().split("T")[0];
    if (dow !== 0 && dow !== 6 && !TW_HOLIDAYS.has(ds)) days++;
    cur.setDate(cur.getDate() + 1);
  }
  return days;
}

function getRemainingWorkDays(startStr, limitDays) {
  if (!startStr) return null;
  const start = new Date(startStr);
  let count = 0;
  const cur = new Date(start);
  while (count < limitDays) {
    cur.setDate(cur.getDate() + 1);
    const dow = cur.getDay();
    const ds = cur.toISOString().split("T")[0];
    if (dow !== 0 && dow !== 6 && !TW_HOLIDAYS.has(ds)) count++;
  }
  const today = new Date();
  today.setHours(0,0,0,0);
  let remaining = 0;
  const tmp = new Date(today);
  while (tmp <= cur) {
    const dow = tmp.getDay();
    const ds = tmp.toISOString().split("T")[0];
    if (dow !== 0 && dow !== 6 && !TW_HOLIDAYS.has(ds)) remaining++;
    tmp.setDate(tmp.getDate() + 1);
  }
  return { deadline: cur.toISOString().split("T")[0], remaining: remaining - 1 };
}

