function getDailyQuote() {
  const now = new Date();
  const hour = now.getHours();
  const day = now.getDate() + now.getMonth() * 31 + now.getFullYear() * 365;
  let slot = 0;
  if (hour >= 8 && hour < 14) slot = 1;
  else if (hour >= 14 && hour < 19) slot = 2;
  else if (hour >= 19) slot = 3;
  const idx = (day * 4 + slot) % DESIGN_QUOTES.length;
  return DESIGN_QUOTES[idx];
}

// ── 今日案件提醒 ──
function getDailyAlert(projects) {
  const today = new Date();
  today.setHours(0, 0, 0, 0);

  // 掃描所有案件
  for (const p of projects) {
    if (p.stage === "提案中" && p.consultDate) {
      const result = getRemainingWorkDays(p.consultDate, 15);
      if (result && !p.proposalDate) {
        if (result.remaining <= 0) return { type: "danger", text: `🚨 「${p.name}」提案已超過 15 工作天！`, id: p.id };
        if (result.remaining <= 3) return { type: "warning", text: `⚠️ 「${p.name}」提案只剩 ${result.remaining} 天！`, id: p.id };
      }
    }
    if (p.stage === "已簽約") {
      const lastMeeting = (p.signedMeetingDates || []).filter(m => m.start).slice(-1)[0];
      if (lastMeeting) {
        const result = getRemainingWorkDays(lastMeeting.start, 10);
        if (result) {
          const allDone = p.layoutFinalDate && p.render3dFinalDate && p.planDrawingDate;
          if (!allDone) {
            if (result.remaining <= 0) return { type: "danger", text: `🚨 「${p.name}」交件已超過 10 工作天！`, id: p.id };
            if (result.remaining <= 3) return { type: "warning", text: `⚠️ 「${p.name}」交件只剩 ${result.remaining} 天！`, id: p.id };
          }
        }
      }
    }
  }

  // 本月完工
  const thisMonth = today.getMonth();
  const thisYear = today.getFullYear();
  const completedThisMonth = projects.filter(p => {
    if (p.stage !== "完工" || !p.closedDate) return false;
    const d = new Date(p.closedDate);
    return d.getMonth() === thisMonth && d.getFullYear() === thisYear;
  }).length;
  if (completedThisMonth > 0) return { type: "success", text: `🎉 本月已完工 ${completedThisMonth} 件，繼續保持！`, id: null };

  // 施工中進度提醒
  const stuckProject = projects.find(p => p.stage === "施工中" && p.progress === 0 && p.startDate);
  if (stuckProject) return { type: "info", text: `📋 「${stuckProject.name}」施工進度還是 0%，記得更新`, id: stuckProject.id };

  return { type: "normal", text: "✨ 今日一切正常，全力以赴！", id: null };
}

