const num = (v) => parseFloat(v) || 0;
const fmtMoney = (n) => (!n && n !== 0) ? "—" : Math.round(n).toLocaleString();

function calcProfit(p) {
  const basePrice = Object.values(p.quote || {}).reduce((s, v) => s + num(v.price), 0);
  const totalCost = Object.values(p.quote || {}).reduce((s, v) => s + num(v.cost), 0);
  const totalChangeOrders = Object.values(p.changeOrders || {}).reduce((s, v) => s + num(v), 0);
  const totalPrice = basePrice + totalChangeOrders;
  const totalBilling = Object.values(p.billing || {}).reduce((s, v) => s + num(v), 0);

  const collectedExtra = (p.extraItems || []).filter(e => e.collected);
  const extraRevenue = collectedExtra.reduce((s, e) => s + num(e.price), 0);
  const extraCost = collectedExtra.reduce((s, e) => s + num(e.cost), 0);
  const extraProfit = extraRevenue - extraCost;

  const totalAbsorbed = (p.absorbedCosts || []).reduce((s, a) => s + num(a.amount), 0);

  const grossProfit = totalPrice - totalCost + extraProfit - totalAbsorbed;
  const grossProfitPct = totalPrice > 0 ? (grossProfit / (totalPrice + extraRevenue)) * 100 : 0;

  const netProfit = totalPrice - totalBilling + extraProfit - totalAbsorbed;
  const netProfitPct = (totalPrice + extraRevenue) > 0 ? (netProfit / (totalPrice + extraRevenue)) * 100 : 0;

  const totalPayments = (p.payments || []).reduce((s, v) => s + num(v.amount), 0);
  const collectRate = totalPrice > 0 ? totalPayments / totalPrice : 0;

  return {
    basePrice, totalPrice, totalCost, totalBilling,
    totalChangeOrders, extraRevenue, extraCost, extraProfit,
    totalAbsorbed, grossProfit, grossProfitPct,
    netProfit, netProfitPct,
    totalPayments, collectRate,
    profit: totalPrice - totalBilling,
    finalProfit: netProfit,
    profitPct: netProfitPct,
  };
}

function batteryColor(pct) {
  if (pct >= 100) return "#50c878";
  if (pct >= 60) return "#5b8af0";
  if (pct >= 30) return "#f0a850";
  return "#e05b5b";
}

