function ProjectCard({ p, onClick, allUsers = [] }) {
  const { totalPrice, netProfitPct } = calcProfit(p);
  const pct = p.progress;
  const bColor = batteryColor(pct);

  // 找負責設計師的職稱顏色
  const ownerUser = allUsers.find(u => u.name === p.designer);
  const ownerColor = ownerUser ? (ROLE_COLORS[ownerUser.role] || "#f0a850") : "#f0a850";

  return (
    <div onClick={onClick} className="glass-card" style={{ borderLeft: `3px solid ${STAGE_COLORS[p.stage]}`, borderRadius: 14, marginBottom: 10, cursor: "pointer", overflow: "hidden", transition: "transform 0.15s" }}
      onMouseEnter={e => e.currentTarget.style.transform = "translateY(-2px)"}
      onMouseLeave={e => e.currentTarget.style.transform = "translateY(0)"}>

      {/* 主要內容區 */}
      <div style={{ padding: "14px 16px 10px" }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 6 }}>
          <div style={{ flex: 1, paddingRight: 10 }}>
            {/* 案件名稱 + 負責人 */}
            <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 3, flexWrap: "wrap" }}>
              <div style={{ fontSize: 15, fontWeight: 600, color: "#f0ead8" }}>{p.name}</div>
              {p.designer && (
                <span style={{ fontSize: 11, fontWeight: 700, color: ownerColor, background: `${ownerColor}18`, border: `1px solid ${ownerColor}30`, borderRadius: 5, padding: "1px 7px", flexShrink: 0 }}>
                  {p.designer}
                </span>
              )}
            </div>
            <div style={{ fontSize: 12, color: "#555" }}>{p.client} · {p.address}</div>
          </div>
          <StageTag stage={p.stage} />
        </div>

        {/* 施工進度條 */}
        {(p.stage === "施工中" || p.stage === "完工") && (
          <div style={{ marginTop: 8 }}>
            <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 4 }}>
              <span style={{ fontSize: 11, color: "#444" }}>施工進度</span>
              <span style={{ fontSize: 11, color: bColor, fontWeight: 600 }}>{pct}%</span>
            </div>
            <div style={{ height: 6, background: "rgba(255,255,255,0.08)", borderRadius: 3, overflow: "hidden" }}>
              <div style={{ height: "100%", width: `${pct}%`, background: bColor, borderRadius: 3, transition: "width 0.4s" }} />
            </div>
            {p.stage === "完工" && totalPrice > 0 && (
              <div style={{ marginTop: 5, fontSize: 11, color: netProfitPct < 20 ? "#50c878" : netProfitPct < 25 ? "#888" : "#f0a850" }}>
                淨利率 {netProfitPct.toFixed(1)}% {netProfitPct < 20 ? "⚠️ 危險" : netProfitPct >= 25 ? "🔥 暴利" : ""}
              </div>
            )}
          </div>
        )}

        {/* 提案進度提示 */}
        {p.stage === "提案中" && p.consultDate && (() => {
          const result = getRemainingWorkDays(p.consultDate, 15);
          if (!result) return null;
          const { remaining } = result;
          if (p.proposalDate) return <div style={{ fontSize: 10, color: "#50c878", marginTop: 6 }}>✅ 提案時間已訂</div>;
          if (remaining <= 0) return <div style={{ fontSize: 10, color: "#e05b5b", marginTop: 6 }}>🚨 已超過15工作天！</div>;
          if (remaining <= 3) return <div style={{ fontSize: 10, color: "#f06450", marginTop: 6 }}>⚠️ 剩 {remaining} 天！快訂提案時間</div>;
          if (remaining <= 7) return <div style={{ fontSize: 10, color: "#f0a850", marginTop: 6 }}>📋 剩 {remaining} 工作天</div>;
          return null;
        })()}
      </div>

      {/* 底部資訊區（方向三：淡底色） */}
      <div style={{ background: "rgba(255,255,255,0.03)", borderTop: "1px solid rgba(255,255,255,0.06)", padding: "7px 16px", fontSize: 11, color: "#888" }}>
        {p.consultDate && `諮詢：${p.consultDate}`}{p.budget && ` · 預算：${p.budget}`}
        {!p.consultDate && !p.budget && "尚無基本資料"}
      </div>
    </div>
  );
}

